import axios from "axios"
const url = "http://localhost:8080/";
export const getAll = async() => {
    try {
        const {data}=await axios.get(`${url}/getAllRobots`)
        return data;
    }
    catch(e) {
        console.log(e)
    }
}

export const getById = async(id) => {
        try {
        const {data}=await axios.get(`${url}/getRobotById/${id}`)
        return data;
    }
    catch(e) {
        console.log(e)
    }

}
